class DataLoader extends EventEmitter {
  async load() {
    this.emit('start');
    try {
      const data = await new Promise((res) => setTimeout(() => res([1, 2, 3]), 1000));
      this.emit('progress', 50);
      await new Promise((res) => setTimeout(res, 1000));
      this.emit('done', data);
    } catch (err) {
      this.emit('error', err);
    }
  }
}

const loader = new DataLoader();

loader.on('start', () => console.log('Загрузка началась...'));
loader.on('progress', (p) => console.log(`Прогресс: ${p}%`));
loader.on('done', (data) => console.log('Готово:', data));
